            label: String::new(),
            symbol: b.to_string(),
            found: true,
            path: entry.path.clone(),
            source: entry.source.clone(),
            line: entry.line,
            epoch: entry.epoch,
            reused,
            fresh,
        }
    } else {
        Observation::missing(b, b, a.epoch, !c)
