pub fn phase_a(a: &mut State, b: &Event, c: &mut CaseReport) -> Result<(), String> {
    match b.kind.as_str() {
        "slot" => {
            if b.left == "gen" {
                emit_c(a, &b.left, &b.right)?;
            } else if b.left == "pkg" {
