            }
        }
        "miss" => {
            let item = mote_e(a, &b.right, false);
            let (item, note) = cast_f(a, item, false);
            c.observations.push(crate::model::Observation { label: b.left.clone(), ..item });
            if let Some(note) = note {
                c.stale.push(note);
            }
        }
        other => return Err(format!("unknown trace row {other}")),
    }
    Ok(())
}
