/// Map trace roots that mention older fixture layouts to the currently-active
/// layout.
///
/// Notes:
/// * app workspaces: ws-old -> ws-new, app-old -> app-new
/// * linked packages: alias-a -> alias-b (the active link)
/// * generated outputs: most cases should prefer the newest generation, but the
///   epsilon trace specifically audits deletion across generations, so we do not
///   rewrite epsilon's gen roots.
pub fn resolve_fixture_root(root: &str) -> String {
    let abs = app_path(root);
    let abs = abs.replace("/ws-old", "/ws-new").replace("/app-old", "/app-new");

    // Prefer the active target for linked package aliases.
    let abs = abs.replace("/alias-a", "/alias-b");

    // Prefer newest generated output, except for epsilon where gen-v1 and gen-v2
    // are intentionally distinct.
    if abs.contains("/fixtures/epsilon/") {
        abs
    } else {
        abs.replace("/gen-v1", "/gen-v2")
    }
}

